chrome.runtime.onMessage.addListener(i=>{if((i==null?void 0:i.type)==="PRICE_DROP"){const t=i.product;chrome.notifications.create(`price-drop-${t.asin}`,{type:"basic",iconUrl:"public/icons/icon128.png",title:"Price drop! 📉",message:`${t.title} is now $${t.currentPrice.toFixed(2)}`,priority:1})}});chrome.runtime.onInstalled.addListener(()=>{console.log("PriceHawk installed. Browse an Amazon product page to start tracking.")});
